const HTML="<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\"/>\n<meta name=\"viewport\" content=\"width=device-width,initial-scale=1.0\"/>\n<title>HVAC Tracker</title>\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/react/18.2.0/umd/react.production.min.js\"></script>\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/react-dom/18.2.0/umd/react-dom.production.min.js\"></script>\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/babel-standalone/7.23.2/babel.min.js\"></script>\n<style>\n*{box-sizing:border-box;margin:0;padding:0}\nbody{background:#0a0a0a;color:#e5e5e5;font-family:'Courier New',monospace}\n::-webkit-scrollbar{width:4px}::-webkit-scrollbar-track{background:#111}::-webkit-scrollbar-thumb{background:#333}\ninput,select,textarea,button{font-family:'Courier New',monospace}\nselect option{background:#111;color:#e5e5e5}\n</style>\n</head>\n<body><div id=\"root\"></div>\n<script type=\"text/babel\">\nconst {useState,useEffect,useCallback}=React;\nconst ANT_KEY=\"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\";\n\n// Auth\nasync function authSignUp(email,password,name,role){\n  const r=await fetch(\"/auth/signup\",{method:\"POST\",headers:{\"Content-Type\":\"application/json\",\"apikey\":\"eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InhsandvbXprdGFncGFjZHVicWR5Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3Nzk0MDEyMDYsImV4cCI6MjA5NDk3NzIwNn0._jUS2bZ119SYhzAr17m8t7tTLWW9mSqY3QhDlq9wujY\"},body:JSON.stringify({email,password,data:{name,role}})});\n  const d=await r.json();if(!r.ok)throw new Error(d.error_description||d.msg||\"Signup failed\");return d;\n}\nasync function authSignIn(email,password){\n  const r=await fetch(\"/auth/token?grant_type=password\",{method:\"POST\",headers:{\"Content-Type\":\"application/json\",\"apikey\":\"eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InhsandvbXprdGFncGFjZHVicWR5Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3Nzk0MDEyMDYsImV4cCI6MjA5NDk3NzIwNn0._jUS2bZ119SYhzAr17m8t7tTLWW9mSqY3QhDlq9wujY\"},body:JSON.stringify({email,password})});\n  const d=await r.json();if(!r.ok)throw new Error(d.error_description||d.msg||\"Login failed\");return d;\n}\nasync function authSignOut(token){await fetch(\"/auth/logout\",{method:\"POST\",headers:{\"Authorization\":\"Bearer \"+token,\"apikey\":\"eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InhsandvbXprdGFncGFjZHVicWR5Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3Nzk0MDEyMDYsImV4cCI6MjA5NDk3NzIwNn0._jUS2bZ119SYhzAr17m8t7tTLWW9mSqY3QhDlq9wujY\"}});}\nasync function authGetUser(token){\n  const r=await fetch(\"/auth/user\",{headers:{\"Authorization\":\"Bearer \"+token,\"apikey\":\"eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InhsandvbXprdGFncGFjZHVicWR5Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3Nzk0MDEyMDYsImV4cCI6MjA5NDk3NzIwNn0._jUS2bZ119SYhzAr17m8t7tTLWW9mSqY3QhDlq9wujY\"}});\n  return r.ok?r.json():null;\n}\nconst SUPABASE_KEY=\"eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InhsandvbXprdGFncGFjZHVicWR5Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3Nzk0MDEyMDYsImV4cCI6MjA5NDk3NzIwNn0._jUS2bZ119SYhzAr17m8t7tTLWW9mSqY3QhDlq9wujY\";\nfunction getSession(){try{return JSON.parse(localStorage.getItem(\"hvac_sess\")||\"null\")}catch(e){return null}}\nfunction saveSession(s){try{localStorage.setItem(\"hvac_sess\",JSON.stringify(s))}catch(e){}}\nfunction clearSess(){try{localStorage.removeItem(\"hvac_sess\")}catch(e){}}\n\n// DB\nfunction hdrs(token){return{\"Content-Type\":\"application/json\",\"apikey\":\"eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InhsandvbXprdGFncGFjZHVicWR5Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3Nzk0MDEyMDYsImV4cCI6MjA5NDk3NzIwNn0._jUS2bZ119SYhzAr17m8t7tTLWW9mSqY3QhDlq9wujY\",\"Authorization\":\"Bearer \"+(token||\"eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InhsandvbXprdGFncGFjZHVicWR5Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3Nzk0MDEyMDYsImV4cCI6MjA5NDk3NzIwNn0._jUS2bZ119SYhzAr17m8t7tTLWW9mSqY3QhDlq9wujY\"),\"Accept\":\"application/json\",\"X-User-Token\":token||\"\"}}\nasync function dbGet(token){\n  const r=await fetch(\"/api/units?order=created_at.asc\",{headers:hdrs(token)});\n  if(!r.ok)throw new Error(await r.text());\n  return (await r.json()).map(function(row){\n    let sp={};try{sp=JSON.parse(row.specs||\"{}\")}catch(e){}\n    return {id:row.id,serialNumber:row.serial_number,make:row.make,model:row.model,floor:row.floor,location:row.location,status:row.status,pmStatus:row.pm_status,lastPM:row.last_pm,nextPM:row.next_pm,installDate:row.install_date,notes:row.notes,photoBase64:row.photo_base64||\"\",diagramBase64:row.diagram_base64||\"\",createdAt:row.created_at,logs:row.logs||[],volts:sp.volts||\"\",hz:sp.hz||\"\",compRLA:sp.compRLA||\"\",lra:sp.lra||\"\",evapFanAmps:sp.evapFanAmps||\"\",refrigerantType:sp.refrigerantType||\"\",totalCharge:sp.totalCharge||\"\",highSidePSI:sp.highSidePSI||\"\",lowSidePSI:sp.lowSidePSI||\"\"};\n  });\n}\nfunction toRow(unit){\n  return {id:unit.id,serial_number:unit.serialNumber,make:unit.make,model:unit.model,floor:unit.floor,location:unit.location,status:unit.status,pm_status:unit.pmStatus,last_pm:unit.lastPM,next_pm:unit.nextPM,install_date:unit.installDate,notes:unit.notes,photo_base64:unit.photoBase64||null,diagram_base64:unit.diagramBase64||null,created_at:unit.createdAt,logs:unit.logs||[],specs:JSON.stringify({volts:unit.volts,hz:unit.hz,compRLA:unit.compRLA,lra:unit.lra,evapFanAmps:unit.evapFanAmps,refrigerantType:unit.refrigerantType,totalCharge:unit.totalCharge,highSidePSI:unit.highSidePSI,lowSidePSI:unit.lowSidePSI})};\n}\nasync function dbSave(token,unit){\n  const r=await fetch(\"/api/units\",{method:\"POST\",headers:Object.assign({},hdrs(token),{\"Prefer\":\"resolution=merge-duplicates,return=representation\"}),body:JSON.stringify(toRow(unit))});\n  if(!r.ok)throw new Error(await r.text());\n}\nasync function dbUpdate(token,unit){\n  const row=toRow(unit);delete row.id;delete row.created_at;\n  const r=await fetch(\"/api/units?id=eq.\"+unit.id,{method:\"PATCH\",headers:hdrs(token),body:JSON.stringify(row)});\n  if(!r.ok)throw new Error(await r.text());\n}\nasync function dbDelete(token,id){\n  const r=await fetch(\"/api/units?id=eq.\"+id,{method:\"DELETE\",headers:hdrs(token)});\n  if(!r.ok)throw new Error(await r.text());\n}\n\n// Utils\nfunction addMonths(ds,n){const d=new Date(ds);d.setMonth(d.getMonth()+n);return d.toISOString().split(\"T\")[0]}\nfunction fmtDate(ds){if(!ds)return\"--\";return new Date(ds).toLocaleDateString(\"en-US\",{year:\"numeric\",month:\"short\",day:\"numeric\"})}\nfunction localDate(){const d=new Date();const m=String(d.getMonth()+1).padStart(2,\"0\");const dy=String(d.getDate()).padStart(2,\"0\");return d.getFullYear()+\"-\"+m+\"-\"+dy}\nfunction getSavedBrands(){try{return JSON.parse(localStorage.getItem(\"hvac_brands\")||\"{}\")}catch(e){return{}}}\nfunction saveBrand(make,model){const b=getSavedBrands();if(!b[make])b[make]=[];if(model&&!b[make].includes(model))b[make].push(model);try{localStorage.setItem(\"hvac_brands\",JSON.stringify(b))}catch(e){}}\nfunction getAllMakes(){return Object.keys(getSavedBrands()).sort()}\nfunction getModels(make){return(getSavedBrands()[make]||[]).sort()}\nfunction compressImage(file,maxW){\n  return new Promise(function(res){\n    const img=new Image();const url=URL.createObjectURL(file);\n    img.onload=function(){\n      const scale=Math.min(1,maxW/img.width);\n      const c=document.createElement(\"canvas\");\n      c.width=Math.round(img.width*scale);c.height=Math.round(img.height*scale);\n      c.getContext(\"2d\").drawImage(img,0,0,c.width,c.height);\n      URL.revokeObjectURL(url);\n      res(c.toDataURL(\"image/jpeg\",0.80).split(\",\")[1]);\n    };\n    img.onerror=function(){URL.revokeObjectURL(url);res(null)};\n    img.src=url;\n  });\n}\n\n// Parts tracking\nconst PARTS=[\n  {key:\"compressor\",label:\"Compressor\",re:/compressor/i},\n  {key:\"reversingValve\",label:\"Reversing Valve\",re:/reversing valve/i},\n  {key:\"capacitor\",label:\"Capacitor\",re:/capacitor/i},\n  {key:\"overload\",label:\"Overload Switch\",re:/overload/i},\n  {key:\"relay\",label:\"Relay\",re:/\\brelay\\b/i},\n  {key:\"thermostat\",label:\"Thermostat\",re:/thermostat/i},\n  {key:\"contactor\",label:\"Contactor\",re:/contactor/i},\n  {key:\"filter\",label:\"Filter\",re:/\\bfilter\\b/i},\n  {key:\"coil\",label:\"Coil\",re:/\\bcoil\\b/i},\n  {key:\"blower\",label:\"Blower Motor\",re:/blower/i},\n];\nfunction countParts(logs){\n  const c={};\n  PARTS.forEach(function(p){c[p.key]=logs.filter(function(l){return l.type!==\"PM\"&&p.re.test(l.description)}).length});\n  return c;\n}\n\n// Pattern analysis\nconst SC={\"Operational\":\"#22c55e\",\"Needs PM\":\"#f59e0b\",\"Under Repair\":\"#ef4444\",\"Out of Service\":\"#6b7280\"};\nconst PC={\"Current\":\"#22c55e\",\"Due Soon\":\"#f59e0b\",\"Overdue\":\"#ef4444\"};\nconst TC={PM:\"#22c55e\",Repair:\"#ef4444\",Inspection:\"#3b82f6\",Note:\"#a855f7\",Emergency:\"#f97316\",Refrigerant:\"#06b6d4\"};\nconst UNIT_STATUS=[\"Operational\",\"Needs PM\",\"Under Repair\",\"Out of Service\"];\nconst PM_LIST=[\"Current\",\"Due Soon\",\"Overdue\"];\nconst FLOORS=[\"North Lobby\",\"South Lobby\",\"3S\",\"4S\",\"5S\",\"5\",\"6S\",\"6\",\"7S\",\"7\",\"8S\",\"8\",\"9\",\"10\",\"11\",\"12\",\"13\",\"14\",\"15\",\"Rooftop\",\"Mechanical Room\",\"Engineer Shop\",\"Other\"];\nconst LOG_TYPES=[\"PM\",\"Repair\",\"Inspection\",\"Refrigerant\",\"Note\",\"Emergency\"];\n\nfunction analyze(unit){\n  const logs=unit.logs||[];const alerts=[];\n  const repairs=logs.filter(function(l){return l.type===\"Repair\"});\n  const refLogs=logs.filter(function(l){return l.type===\"Refrigerant\"||/leak|low pressure|refrigerant|freon|charge/i.test(l.description)});\n  if(refLogs.length>=2)alerts.push({level:\"critical\",icon:\"\ud83d\udd34\",title:\"RECURRING REFRIGERANT LEAK (\"+refLogs.length+\"x)\",detail:\"Repeated recharging indicates an active leak.\",actions:[\"Stop recharging \u2014 find and fix the leak.\",\"Pull unit, pressure test at shop.\",\"Coil/compressor leak: REPLACE UNIT.\",\"Document all refrigerant additions (EPA 608).\"]});\n  else if(refLogs.length===1)alerts.push({level:\"warning\",icon:\"\ud83d\udfe1\",title:\"REFRIGERANT EVENT LOGGED\",detail:\"One event. Monitor \u2014 second confirms a leak.\",actions:[\"Check fittings for oil residue.\",\"Use leak detector at next PM.\"]});\n  if(repairs.length>=3){\n    const sorted=[].concat(repairs).sort(function(a,b){return new Date(a.date)-new Date(b.date)});\n    const span=Math.round((new Date(sorted[sorted.length-1].date)-new Date(sorted[0].date))/86400000);\n    const pyr=span>0?(repairs.length/(span/365)).toFixed(1):repairs.length;\n    alerts.push({level:repairs.length>=5?\"critical\":\"warning\",icon:repairs.length>=5?\"\ud83d\udd34\":\"\ud83d\udfe1\",title:\"HIGH REPAIR FREQUENCY (\"+repairs.length+\" repairs, ~\"+pyr+\"/yr)\",detail:\"Units averaging 2+ repairs/year are not cost-effective.\",actions:[\"Compare repair costs vs new unit.\",\"Budget for replacement if 5+ repairs.\"]});\n  }\n  const compLogs=logs.filter(function(l){return/compressor/i.test(l.description)});\n  if(compLogs.length>=2)alerts.push({level:\"critical\",icon:\"\ud83d\udd34\",title:\"RECURRING COMPRESSOR ISSUES (\"+compLogs.length+\"x)\",detail:\"Compressor repairs cost 50-70% of new unit.\",actions:[\"RECOMMEND UNIT REPLACEMENT.\",\"Check electrical supply voltage.\",\"Verify refrigerant charge.\"]});\n  const elecLogs=logs.filter(function(l){return/capacitor|contactor|electrical|fuse|breaker|relay/i.test(l.description)});\n  if(elecLogs.length>=2)alerts.push({level:\"warning\",icon:\"\ud83d\udfe1\",title:\"RECURRING ELECTRICAL ISSUES (\"+elecLogs.length+\"x)\",detail:\"Multiple electrical component failures.\",actions:[\"Check voltage within 10% of nameplate.\",\"Replace capacitors/contactors at next PM.\"]});\n  if(unit.nextPM){const over=Math.round((new Date(localDate())-new Date(unit.nextPM))/86400000);if(over>30)alerts.push({level:\"warning\",icon:\"\ud83d\udfe1\",title:\"PM OVERDUE BY \"+over+\" DAYS\",detail:\"Deferred PMs increase failure risk.\",actions:[\"Schedule PM immediately.\"]});}\n  if(alerts.length===0&&logs.length>=2)alerts.push({level:\"good\",icon:\"\u2705\",title:\"NO RECURRING ISSUES DETECTED\",detail:logs.length+\" entries analyzed. Unit appears normal.\",actions:[\"Continue PM every 4 months.\",\"Monitor refrigerant pressure at each PM.\"]});\n  return alerts;\n}\n\n// Styles\nconst INP={width:\"100%\",background:\"#0d0d0d\",border:\"1px solid #2e2e2e\",borderRadius:\"3px\",color:\"#e5e5e5\",padding:\"0.5rem 0.6rem\",fontSize:\"0.82rem\",boxSizing:\"border-box\",outline:\"none\"};\nconst SEL=Object.assign({},INP,{cursor:\"pointer\"});\nconst TA=Object.assign({},INP,{resize:\"vertical\",minHeight:\"80px\"});\n\nfunction Modal(props){\n  return <div style={{position:\"fixed\",inset:0,background:\"rgba(0,0,0,0.85)\",zIndex:1000,display:\"flex\",alignItems:\"center\",justifyContent:\"center\",padding:\"1rem\",overflowY:\"auto\"}}>\n    <div style={{background:\"#161616\",border:\"1px solid #2e2e2e\",borderRadius:\"4px\",width:\"100%\",maxWidth:\"640px\",maxHeight:\"95vh\",overflow:\"auto\"}}>\n      <div style={{display:\"flex\",justifyContent:\"space-between\",alignItems:\"center\",padding:\"0.9rem 1.25rem\",borderBottom:\"1px solid #2a2a2a\",background:\"#111\",position:\"sticky\",top:0,zIndex:1}}>\n        <span style={{color:\"#f59e0b\",fontSize:\"0.8rem\",letterSpacing:\"0.12em\",textTransform:\"uppercase\"}}>{props.title}</span>\n        <button onClick={props.onClose} style={{background:\"none\",border:\"none\",color:\"#666\",cursor:\"pointer\",fontSize:\"1.2rem\"}}>X</button>\n      </div>\n      <div style={{padding:\"1.25rem\"}}>{props.children}</div>\n    </div>\n  </div>;\n}\n\nfunction Field(props){\n  return <div style={{marginBottom:\"0.8rem\"}}>\n    <label style={{display:\"block\",fontSize:\"0.62rem\",color:\"#777\",letterSpacing:\"0.1em\",textTransform:\"uppercase\",marginBottom:\"0.28rem\"}}>{props.label}</label>\n    {props.children}\n  </div>;\n}\n\nfunction AlertCard(props){\n  const a=props.alert;\n  const bg=a.level===\"critical\"?\"#1a0505\":a.level===\"warning\"?\"#1a1205\":\"#051a09\";\n  const border=a.level===\"critical\"?\"#5a1010\":a.level===\"warning\"?\"#5a4010\":\"#105a20\";\n  const color=a.level===\"critical\"?\"#f87171\":a.level===\"warning\"?\"#fbbf24\":\"#4ade80\";\n  return <div style={{background:bg,border:\"1px solid \"+border,borderRadius:\"4px\",padding:\"0.9rem 1rem\",marginBottom:\"0.75rem\"}}>\n    <div style={{fontSize:\"0.78rem\",fontWeight:\"bold\",color:color,marginBottom:\"0.4rem\"}}>{a.icon} {a.title}</div>\n    <div style={{fontSize:\"0.78rem\",color:\"#bbb\",marginBottom:\"0.6rem\",lineHeight:1.5}}>{a.detail}</div>\n    <div style={{borderTop:\"1px solid \"+border,paddingTop:\"0.5rem\"}}>\n      <div style={{fontSize:\"0.65rem\",color:\"#666\",letterSpacing:\"0.08em\",marginBottom:\"0.35rem\"}}>RECOMMENDED ACTIONS</div>\n      {a.actions.map(function(x,i){return <div key={i} style={{fontSize:\"0.76rem\",color:\"#ccc\",padding:\"0.2rem 0\",lineHeight:1.5}}>{x}</div>})}\n    </div>\n  </div>;\n}\n\nfunction PartsTab(props){\n  const counts=countParts(props.unit.logs||[]);\n  const hasParts=PARTS.some(function(p){return counts[p.key]>0});\n  return <div>\n    <div style={{fontSize:\"0.68rem\",color:\"#555\",letterSpacing:\"0.08em\",marginBottom:\"0.85rem\"}}>PARTS REPLACEMENT HISTORY</div>\n    {!hasParts&&<div style={{color:\"#444\",fontSize:\"0.8rem\",padding:\"1.5rem 0\",textAlign:\"center\"}}>No parts replacements logged yet. Mention part names in repair entries.</div>}\n    <div style={{display:\"grid\",gridTemplateColumns:\"1fr 1fr\",gap:\"0.5rem\"}}>\n      {PARTS.map(function(p){\n        const c=counts[p.key];\n        const color=c>=3?\"#f87171\":c>=2?\"#fbbf24\":c>=1?\"#22c55e\":\"#333\";\n        const bg=c>=3?\"#1a0505\":c>=2?\"#1a1205\":c>=1?\"#051a09\":\"#111\";\n        return <div key={p.key} style={{background:bg,border:\"1px solid \"+(c>0?color:\"#222\"),borderRadius:\"3px\",padding:\"0.6rem 0.75rem\",display:\"flex\",justifyContent:\"space-between\",alignItems:\"center\"}}>\n          <span style={{fontSize:\"0.72rem\",color:c>0?\"#ccc\":\"#555\"}}>{p.label}</span>\n          <span style={{fontSize:\"1rem\",fontWeight:\"bold\",color:c>0?color:\"#333\"}}>{c}</span>\n        </div>;\n      })}\n    </div>\n    {hasParts&&<div style={{marginTop:\"0.75rem\",padding:\"0.6rem 0.85rem\",background:\"#111\",borderRadius:\"3px\",border:\"1px solid #222\",fontSize:\"0.72rem\",color:\"#888\"}}>\n      Red 3+ = critical | Yellow 2 = monitor | Green 1 = normal\n    </div>}\n  </div>;\n}\n\nfunction TroubleshootTab(props){\n  const unit=props.unit;\n  const [symptom,setSymptom]=useState(\"\");\n  const [result,setResult]=useState(\"\");\n  const [loading,setLoading]=useState(false);\n  const [showDiag,setShowDiag]=useState(false);\n  function run(){\n    if(!symptom.trim())return;\n    setLoading(true);setResult(\"\");\n    const counts=countParts(unit.logs||[]);\n    const partsHist=PARTS.filter(function(p){return counts[p.key]>0}).map(function(p){return p.label+\": \"+counts[p.key]+\"x\"}).join(\", \")||\"None recorded\";\n    const hist=(unit.logs||[]).slice(-6).map(function(l){return \"[\"+l.type+\"] \"+l.date+\": \"+l.description}).join(\"\\n\")||\"No history\";\n    const specsStr=[unit.volts&&\"Volts: \"+unit.volts,unit.refrigerantType&&\"Ref: \"+unit.refrigerantType,unit.totalCharge&&\"Charge: \"+unit.totalCharge+\" lbs\",unit.compRLA&&\"RLA: \"+unit.compRLA+\"A\",unit.highSidePSI&&\"High: \"+unit.highSidePSI+\" PSI\",unit.lowSidePSI&&\"Low: \"+unit.lowSidePSI+\" PSI\"].filter(Boolean).join(\", \")||\"not recorded\";\n    const prompt=\"You are a senior HVAC technician.\\n\\nUNIT: \"+unit.make+\" \"+unit.model+\", Serial: \"+unit.serialNumber+\", Floor: \"+unit.floor+\" \"+(unit.location||\"\")+\"\\nSPECS: \"+specsStr+\"\\nNOTES: \"+(unit.notes||\"none\")+\"\\nPARTS HISTORY: \"+partsHist+\"\\nSERVICE HISTORY:\\n\"+hist+\"\\nSYMPTOM: \"+symptom+\"\\n\\n\"+(unit.diagramBase64?\"A wiring diagram is attached.\":\"No diagram.\")+\"\\n\\nProvide:\\n1. MOST LIKELY CAUSES\\n2. STEP-BY-STEP DIAGNOSTIC\\n3. TOOLS NEEDED\\n4. PARTS TO REPLACE\\n5. SAFETY WARNINGS\\n6. ESTIMATED TIME & COST\";\n    const content=unit.diagramBase64\n      ?[{type:\"image\",source:{type:\"base64\",media_type:\"image/jpeg\",data:unit.diagramBase64}},{type:\"text\",text:prompt}]\n      :[{type:\"text\",text:prompt}];\n    fetch(\"https://api.anthropic.com/v1/messages\",{method:\"POST\",headers:{\"Content-Type\":\"application/json\",\"x-api-key\":ANT_KEY,\"anthropic-version\":\"2023-06-01\",\"anthropic-dangerous-direct-browser-access\":\"true\"},body:JSON.stringify({model:\"claude-sonnet-4-20250514\",max_tokens:1800,messages:[{role:\"user\",content:content}]})})\n      .then(function(r){return r.json()})\n      .then(function(d){setResult((d.content||[]).map(function(b){return b.text||\"\"}).join(\"\").trim());setLoading(false);})\n      .catch(function(e){setResult(\"Error: \"+e.message);setLoading(false);});\n  }\n  return <div>\n    <div style={{display:\"flex\",alignItems:\"center\",gap:\"0.6rem\",marginBottom:\"0.85rem\",padding:\"0.6rem 0.85rem\",background:unit.diagramBase64?\"#050d08\":\"#0d0a05\",border:\"1px solid \"+(unit.diagramBase64?\"#1a4a2a\":\"#3a2a10\"),borderRadius:\"3px\"}}>\n      <span>{unit.diagramBase64?\"\ud83d\udcd0\":\"\u26a0\ufe0f\"}</span>\n      <div style={{flex:1}}>\n        <div style={{fontSize:\"0.72rem\",color:unit.diagramBase64?\"#4ade80\":\"#f59e0b\",fontWeight:\"bold\"}}>{unit.diagramBase64?\"Wiring diagram loaded\":\"No diagram \u2014 using history + general knowledge\"}</div>\n        <div style={{fontSize:\"0.63rem\",color:\"#555\",marginTop:\"1px\"}}>Edit unit to {unit.diagramBase64?\"update\":\"upload\"} a diagram</div>\n      </div>\n      {unit.diagramBase64&&<img src={\"data:image/jpeg;base64,\"+unit.diagramBase64} style={{width:\"44px\",height:\"44px\",objectFit:\"cover\",borderRadius:\"2px\",cursor:\"pointer\"}} onClick={function(){setShowDiag(function(p){return !p})}}/>}\n    </div>\n    {showDiag&&unit.diagramBase64&&<div style={{marginBottom:\"0.85rem\"}}><img src={\"data:image/jpeg;base64,\"+unit.diagramBase64} style={{width:\"100%\",borderRadius:\"3px\",border:\"1px solid #1a4a2a\"}}/><button onClick={function(){setShowDiag(false)}} style={{fontSize:\"0.65rem\",color:\"#555\",background:\"none\",border:\"none\",cursor:\"pointer\",marginTop:\"0.3rem\"}}>Hide</button></div>}\n    <Field label=\"Describe the Problem\">\n      <textarea style={Object.assign({},TA,{minHeight:\"90px\"})} value={symptom} onChange={function(e){setSymptom(e.target.value)}} placeholder=\"e.g. Not cooling, compressor loud, tripping breaker, freezing up...\"/>\n    </Field>\n    <button onClick={run} disabled={loading||!symptom.trim()} style={{background:loading||!symptom.trim()?\"#1a1a1a\":\"#3b82f6\",border:\"none\",color:loading||!symptom.trim()?\"#444\":\"#fff\",padding:\"0.55rem 1.25rem\",borderRadius:\"3px\",cursor:loading||!symptom.trim()?\"not-allowed\":\"pointer\",fontSize:\"0.78rem\",fontWeight:\"bold\",width:\"100%\",marginBottom:\"1rem\"}}>\n      {loading?\"Analyzing...\":\"Run AI Troubleshoot\"}\n    </button>\n    {result&&<div style={{background:\"#080d12\",border:\"1px solid #1a2a3a\",borderRadius:\"4px\",padding:\"1rem\"}}><div style={{fontSize:\"0.62rem\",color:\"#3b82f6\",letterSpacing:\"0.1em\",marginBottom:\"0.75rem\"}}>AI TROUBLESHOOTING REPORT</div><div style={{fontSize:\"0.8rem\",color:\"#d0e0f0\",lineHeight:1.75,whiteSpace:\"pre-wrap\"}}>{result}</div></div>}\n  </div>;\n}\n\nfunction UnitDetail(props){\n  const unit=props.unit;const isAdmin=props.isAdmin;\n  const [tab,setTab]=useState(\"info\");\n  const patterns=analyze(unit);\n  const crit=patterns.filter(function(p){return p.level===\"critical\"}).length;\n  const warn=patterns.filter(function(p){return p.level===\"warning\"}).length;\n  const pc=countParts(unit.logs||[]);\n  const critParts=PARTS.filter(function(p){return pc[p.key]>=3}).length;\n  const tabs=[\n    {id:\"info\",label:\"INFO\"},\n    {id:\"logs\",label:\"HISTORY (\"+(unit.logs?unit.logs.length:0)+\")\"},\n    {id:\"parts\",label:\"PARTS\"+(critParts>0?\" \ud83d\udd34\"+critParts:\"\")},\n    {id:\"analysis\",label:\"ANALYSIS\"+(crit>0?\" \ud83d\udd34\"+crit:warn>0?\" \ud83d\udfe1\"+warn:\" \u2705\")},\n    {id:\"troubleshoot\",label:\"TROUBLESHOOT\"},\n  ];\n  const specs=[[\" Volts\",unit.volts],[\" Hz\",unit.hz],[\"Comp RLA\",unit.compRLA?unit.compRLA+\" A\":\"\"],[\" LRA\",unit.lra?unit.lra+\" A\":\"\"],[\" Evap Fan\",unit.evapFanAmps?unit.evapFanAmps+\" A\":\"\"],[\" Refrigerant\",unit.refrigerantType],[\" Total Charge\",unit.totalCharge?unit.totalCharge+\" lbs\":\"\"],[\" High Side\",unit.highSidePSI?unit.highSidePSI+\" PSI\":\"\"],[\" Low Side\",unit.lowSidePSI?unit.lowSidePSI+\" PSI\":\"\"]].filter(function(kv){return kv[1]});\n  return <div style={{fontFamily:\"Courier New,monospace\"}}>\n    <div style={{display:\"flex\",gap:\"2px\",marginBottom:\"1rem\",borderBottom:\"1px solid #222\",overflowX:\"auto\"}}>\n      {tabs.map(function(t){return <button key={t.id} onClick={function(){setTab(t.id)}} style={{background:tab===t.id?\"#1e1a12\":\"none\",border:\"none\",borderBottom:tab===t.id?\"2px solid #f59e0b\":\"2px solid transparent\",color:tab===t.id?\"#f59e0b\":\"#555\",padding:\"0.5rem 0.75rem\",cursor:\"pointer\",fontSize:\"0.65rem\",letterSpacing:\"0.06em\",whiteSpace:\"nowrap\"}}>{t.label}</button>})}\n    </div>\n    {tab===\"info\"&&<div>\n      <div style={{display:\"grid\",gridTemplateColumns:\"1fr 1fr\",gap:\"0.6rem 1.5rem\",marginBottom:\"1rem\"}}>\n        {[[\"Serial\",unit.serialNumber],[\"Make/Model\",unit.make+(unit.model?\" \"+unit.model:\"\")],[\"Floor\",unit.floor],[\"Location\",unit.location||\"--\"],[\"Status\",unit.status],[\"PM Status\",unit.pmStatus],[\"Install\",fmtDate(unit.installDate)],[\"Last PM\",fmtDate(unit.lastPM)],[\"Next PM\",fmtDate(unit.nextPM)]].map(function(kv){\n          return <div key={kv[0]}><div style={{fontSize:\"0.6rem\",color:\"#555\",letterSpacing:\"0.08em\",textTransform:\"uppercase\",marginBottom:\"2px\"}}>{kv[0]}</div><div style={{color:kv[0]===\"Status\"?SC[kv[1]]||\"#e5e5e5\":kv[0]===\"PM Status\"?PC[kv[1]]||\"#e5e5e5\":\"#e5e5e5\",fontSize:\"0.82rem\"}}>{kv[1]||\"--\"}</div></div>;\n        })}\n      </div>\n      {specs.length>0&&<div style={{background:\"#0a0d0a\",border:\"1px solid #1a3a1a\",borderRadius:\"3px\",padding:\"0.75rem\",marginBottom:\"0.85rem\"}}>\n        <div style={{fontSize:\"0.62rem\",color:\"#f59e0b\",letterSpacing:\"0.1em\",marginBottom:\"0.6rem\"}}>TECHNICAL SPECS</div>\n        <div style={{display:\"grid\",gridTemplateColumns:\"1fr 1fr\",gap:\"0.4rem 1rem\"}}>\n          {specs.map(function(kv){return <div key={kv[0]}><div style={{fontSize:\"0.58rem\",color:\"#4a8a4a\",letterSpacing:\"0.08em\",textTransform:\"uppercase\"}}>{kv[0].trim()}</div><div style={{color:\"#4ade80\",fontSize:\"0.82rem\",fontWeight:\"bold\"}}>{kv[1]}</div></div>})}\n        </div>\n      </div>}\n      {unit.photoBase64&&<div style={{marginBottom:\"0.85rem\"}}><div style={{fontSize:\"0.6rem\",color:\"#555\",marginBottom:\"0.35rem\"}}>UNIT PHOTO</div><img src={\"data:image/jpeg;base64,\"+unit.photoBase64} style={{width:\"100%\",maxHeight:\"200px\",objectFit:\"contain\",borderRadius:\"3px\",border:\"1px solid #222\",background:\"#0a0a0a\"}}/></div>}\n      {unit.diagramBase64&&<div style={{marginBottom:\"0.85rem\"}}><div style={{fontSize:\"0.6rem\",color:\"#4a8a6a\",marginBottom:\"0.35rem\"}}>WIRING DIAGRAM</div><img src={\"data:image/jpeg;base64,\"+unit.diagramBase64} style={{width:\"100%\",maxHeight:\"200px\",objectFit:\"contain\",borderRadius:\"3px\",border:\"1px solid #1a3a2a\",background:\"#080d0a\"}}/></div>}\n      {unit.notes&&<div style={{background:\"#0d0d0d\",border:\"1px solid #222\",borderRadius:\"3px\",padding:\"0.7rem 0.85rem\",marginBottom:\"0.85rem\"}}><div style={{fontSize:\"0.6rem\",color:\"#555\",marginBottom:\"0.35rem\"}}>NOTES</div><div style={{color:\"#bbb\",fontSize:\"0.8rem\",lineHeight:1.6}}>{unit.notes}</div></div>}\n      <div style={{display:\"flex\",justifyContent:\"flex-end\"}}><button onClick={props.onEdit} style={{background:\"#f59e0b\",border:\"none\",color:\"#000\",padding:\"0.45rem 1.1rem\",borderRadius:\"3px\",cursor:\"pointer\",fontSize:\"0.75rem\",fontWeight:\"bold\"}}>EDIT UNIT</button></div>\n    </div>}\n    {tab===\"logs\"&&<div>\n      <div style={{display:\"flex\",justifyContent:\"flex-end\",marginBottom:\"0.75rem\"}}>\n        <button onClick={props.onAddLog} style={{background:\"#22c55e\",border:\"none\",color:\"#000\",padding:\"0.4rem 0.9rem\",borderRadius:\"3px\",cursor:\"pointer\",fontSize:\"0.72rem\",fontWeight:\"bold\"}}>+ ADD LOG ENTRY</button>\n      </div>\n      <div style={{maxHeight:\"380px\",overflowY:\"auto\"}}>\n        {(!unit.logs||unit.logs.length===0)?<div style={{color:\"#444\",fontSize:\"0.8rem\",textAlign:\"center\",padding:\"2.5rem 0\"}}>No service history yet</div>\n        :[].concat(unit.logs).reverse().map(function(log,i){\n          return <div key={i} style={{borderLeft:\"3px solid \"+(TC[log.type]||\"#444\"),paddingLeft:\"0.75rem\",marginBottom:\"1rem\"}}>\n            <div style={{display:\"flex\",gap:\"0.5rem\",alignItems:\"center\",flexWrap:\"wrap\",marginBottom:\"0.25rem\"}}>\n              <span style={{color:TC[log.type]||\"#888\",fontSize:\"0.68rem\",fontWeight:\"bold\",background:(TC[log.type]||\"#444\")+\"22\",padding:\"1px 6px\",borderRadius:\"2px\"}}>{log.type}</span>\n              <span style={{color:\"#666\",fontSize:\"0.68rem\"}}>{fmtDate(log.date)}</span>\n              {log.tech&&<span style={{color:\"#f59e0b\",fontSize:\"0.68rem\",background:\"#1a1200\",padding:\"1px 6px\",borderRadius:\"50px\",fontWeight:\"bold\"}}>{log.tech}</span>}\n              {log.refrigerantAdded&&<span style={{color:\"#06b6d4\",fontSize:\"0.65rem\"}}>\ud83d\udca7 {log.refrigerantAdded} lbs</span>}\n              {log.pressure&&<span style={{color:\"#a855f7\",fontSize:\"0.65rem\"}}>PSI: {log.pressure}</span>}\n              {isAdmin&&<button onClick={function(){props.onDeleteLog(unit.logs.length-1-i)}} style={{marginLeft:\"auto\",background:\"none\",border:\"none\",color:\"#444\",cursor:\"pointer\",fontSize:\"0.65rem\",padding:0}}>X</button>}\n            </div>\n            <div style={{color:\"#ccc\",fontSize:\"0.8rem\",lineHeight:1.55}}>{log.description}</div>\n          </div>;\n        })}\n      </div>\n    </div>}\n    {tab===\"parts\"&&<PartsTab unit={unit}/>}\n    {tab===\"analysis\"&&<div>\n      <div style={{fontSize:\"0.68rem\",color:\"#555\",letterSpacing:\"0.08em\",marginBottom:\"0.85rem\"}}>PATTERN ANALYSIS \u2014 {unit.logs?unit.logs.length:0} LOG ENTRIES SCANNED</div>\n      {(!unit.logs||unit.logs.length<2)?<div style={{color:\"#444\",fontSize:\"0.8rem\",padding:\"2rem 0\",textAlign:\"center\"}}>Add at least 2 log entries to enable analysis.</div>:patterns.map(function(a,i){return <AlertCard key={i} alert={a}/>})}\n    </div>}\n    {tab===\"troubleshoot\"&&<TroubleshootTab unit={unit}/>}\n  </div>;\n}\n\nfunction UnitForm(props){\n  const unit=props.unit;\n  const blank={serialNumber:\"\",make:\"\",model:\"\",location:\"\",floor:\"North Lobby\",status:\"Operational\",pmStatus:\"Current\",lastPM:\"\",nextPM:\"\",installDate:\"\",notes:\"\",photoBase64:\"\",diagramBase64:\"\",volts:\"\",hz:\"\",compRLA:\"\",lra:\"\",evapFanAmps:\"\",refrigerantType:\"\",totalCharge:\"\",highSidePSI:\"\",lowSidePSI:\"\"};\n  const [form,setForm]=useState(unit?Object.assign({},blank,unit):blank);\n  const [scanning,setScanning]=useState(false);\n  const [scanMsg,setScanMsg]=useState(\"\");\n  const [photoPreview,setPhotoPreview]=useState(unit&&unit.photoBase64?\"data:image/jpeg;base64,\"+unit.photoBase64:\"\");\n  const [diagPreview,setDiagPreview]=useState(unit&&unit.diagramBase64?\"data:image/jpeg;base64,\"+unit.diagramBase64:\"\");\n  const [savedMakes]=useState(getAllMakes);\n  const [savedModels,setSavedModels]=useState(function(){return getModels(unit?unit.make:\"\")});\n  function set(k,v){setForm(function(f){return Object.assign({},f,{[k]:v})})}\n  function handleLastPM(v){set(\"lastPM\",v);if(v)set(\"nextPM\",addMonths(v,4))}\n  function handleMake(v){set(\"make\",v);setSavedModels(getModels(v))}\n\n  function handlePhoto(e){\n    const file=e.target.files[0];if(!file)return;\n    setScanning(true);setScanMsg(\"Processing image...\");\n    compressImage(file,1200).then(function(base64){\n      if(!base64){setScanMsg(\"Could not read image.\");setScanning(false);return;}\n      setPhotoPreview(\"data:image/jpeg;base64,\"+base64);\n      set(\"photoBase64\",base64);\n      setScanMsg(\"Scanning nameplate with AI...\");\n      fetch(\"https://api.anthropic.com/v1/messages\",{\n        method:\"POST\",\n        headers:{\"Content-Type\":\"application/json\",\"x-api-key\":ANT_KEY,\"anthropic-version\":\"2023-06-01\",\"anthropic-dangerous-direct-browser-access\":\"true\"},\n        body:JSON.stringify({model:\"claude-sonnet-4-20250514\",max_tokens:600,messages:[{role:\"user\",content:[\n          {type:\"image\",source:{type:\"base64\",media_type:\"image/jpeg\",data:base64}},\n          {type:\"text\",text:'Look at this HVAC unit nameplate. Extract all visible text. Return ONLY valid JSON with these keys: serialNumber, make, model, refrigerantType, voltage, hz, compRLA, lra, tonnage, notes. Use empty string for missing fields.'}\n        ]}]})\n      })\n      .then(function(r){return r.json()})\n      .then(function(d){\n        const text=(d.content||[]).map(function(b){return b.text||\"\"}).join(\"\").trim();\n        const s=text.indexOf(\"{\");const en=text.lastIndexOf(\"}\");\n        if(s===-1){setScanMsg(\"AI could not read nameplate \u2014 fill in manually.\");setScanning(false);return;}\n        const p=JSON.parse(text.slice(s,en+1));\n        setForm(function(f){\n          const extra=[p.refrigerantType&&\"Refrigerant: \"+p.refrigerantType,p.tonnage&&\"Tonnage: \"+p.tonnage,p.notes].filter(Boolean).join(\" | \");\n          return Object.assign({},f,{\n            serialNumber:p.serialNumber||f.serialNumber,\n            make:p.make||f.make,\n            model:p.model||f.model,\n            volts:p.voltage||f.volts,\n            hz:p.hz||f.hz,\n            compRLA:p.compRLA||f.compRLA,\n            lra:p.lra||f.lra,\n            refrigerantType:p.refrigerantType||f.refrigerantType,\n            notes:[f.notes,extra].filter(Boolean).join(\" | \"),\n            photoBase64:base64\n          });\n        });\n        setScanMsg(\"SUCCESS: Nameplate scanned \u2014 review fields below.\");\n        setScanning(false);\n      })\n      .catch(function(err){setScanMsg(\"Scan failed: \"+err.message.slice(0,80));setScanning(false);});\n    });\n  }\n\n  function handleDiagram(e){\n    const file=e.target.files[0];if(!file)return;\n    compressImage(file,1600).then(function(base64){\n      if(base64){setDiagPreview(\"data:image/jpeg;base64,\"+base64);set(\"diagramBase64\",base64);}\n    });\n  }\n\n  function handleSave(){\n    if(!form.serialNumber||!form.make){alert(\"Please fill in Serial Number and Make.\");return;}\n    saveBrand(form.make,form.model);\n    props.onSave(form);\n  }\n\n  return <div>\n    <div style={{marginBottom:\"1rem\",border:\"1px dashed #2e2e2e\",borderRadius:\"4px\",padding:\"0.85rem\",background:\"#0a0a0a\"}}>\n      <div style={{fontSize:\"0.62rem\",color:\"#777\",letterSpacing:\"0.1em\",textTransform:\"uppercase\",marginBottom:\"0.6rem\"}}>NAMEPLATE PHOTO (AI Auto-Fill)</div>\n      <div style={{display:\"flex\",gap:\"0.75rem\",alignItems:\"flex-start\",flexWrap:\"wrap\"}}>\n        {photoPreview&&<img src={photoPreview} style={{width:\"88px\",height:\"88px\",objectFit:\"cover\",borderRadius:\"3px\",border:\"1px solid #2e2e2e\",flexShrink:0}}/>}\n        <div style={{flex:1,minWidth:\"160px\"}}>\n          <label style={{display:\"inline-block\",background:\"#1a1a1a\",border:\"1px solid #3a3a3a\",color:\"#ccc\",padding:\"0.4rem 0.85rem\",borderRadius:\"3px\",cursor:\"pointer\",fontSize:\"0.73rem\"}}>\n            {photoPreview?\"CHANGE PHOTO\":\"UPLOAD / TAKE PHOTO\"}\n            <input type=\"file\" accept=\"image/*\" capture=\"environment\" style={{display:\"none\"}} onChange={handlePhoto}/>\n          </label>\n          <div style={{fontSize:\"0.67rem\",color:\"#555\",marginTop:\"0.4rem\",lineHeight:1.55}}>Point at nameplate \u2014 AI reads serial, make, model, specs.</div>\n          {scanMsg&&<div style={{fontSize:\"0.7rem\",marginTop:\"0.4rem\",color:scanning?\"#f59e0b\":scanMsg.startsWith(\"SUCCESS\")?\"#22c55e\":\"#f87171\"}}>{scanning?\"Loading... \":\"\"}{scanMsg}</div>}\n        </div>\n      </div>\n    </div>\n    <div style={{marginBottom:\"1rem\",border:\"1px dashed #1a3a2a\",borderRadius:\"4px\",padding:\"0.85rem\",background:\"#080d0a\"}}>\n      <div style={{fontSize:\"0.62rem\",color:\"#4a8a6a\",letterSpacing:\"0.1em\",textTransform:\"uppercase\",marginBottom:\"0.6rem\"}}>WIRING / UNIT DIAGRAM (for AI Troubleshooting)</div>\n      <div style={{display:\"flex\",gap:\"0.75rem\",alignItems:\"flex-start\",flexWrap:\"wrap\"}}>\n        {diagPreview&&<img src={diagPreview} style={{width:\"88px\",height:\"88px\",objectFit:\"cover\",borderRadius:\"3px\",border:\"1px solid #1a3a2a\",flexShrink:0}}/>}\n        <div style={{flex:1,minWidth:\"160px\"}}>\n          <label style={{display:\"inline-block\",background:\"#0a1a12\",border:\"1px solid #1a4a2a\",color:\"#4ade80\",padding:\"0.4rem 0.85rem\",borderRadius:\"3px\",cursor:\"pointer\",fontSize:\"0.73rem\"}}>\n            {diagPreview?\"CHANGE DIAGRAM\":\"UPLOAD DIAGRAM\"}\n            <input type=\"file\" accept=\"image/*\" style={{display:\"none\"}} onChange={handleDiagram}/>\n          </label>\n          {diagPreview&&<div style={{fontSize:\"0.7rem\",color:\"#22c55e\",marginTop:\"0.4rem\"}}>Diagram saved</div>}\n          {!diagPreview&&<div style={{fontSize:\"0.67rem\",color:\"#2a5a3a\",marginTop:\"0.4rem\"}}>Upload wiring schematic for precise AI troubleshooting.</div>}\n        </div>\n      </div>\n    </div>\n    <div style={{display:\"grid\",gridTemplateColumns:\"1fr 1fr\",gap:\"0 1rem\"}}>\n      <Field label=\"Serial Number *\"><input style={INP} value={form.serialNumber} onChange={function(e){set(\"serialNumber\",e.target.value)}} placeholder=\"e.g. AC-2024-001\"/></Field>\n      <Field label=\"Make / Brand *\">\n        <input style={INP} list=\"makes-list\" value={form.make} onChange={function(e){handleMake(e.target.value)}} placeholder=\"e.g. Carrier, Trane\"/>\n        <datalist id=\"makes-list\">{savedMakes.map(function(m){return <option key={m} value={m}/>})}</datalist>\n      </Field>\n      <Field label=\"Model\">\n        <input style={INP} list=\"models-list\" value={form.model} onChange={function(e){set(\"model\",e.target.value)}} placeholder=\"e.g. 50XC060\"/>\n        <datalist id=\"models-list\">{savedModels.map(function(m){return <option key={m} value={m}/>})}</datalist>\n      </Field>\n      <Field label=\"Floor / Zone\"><select style={SEL} value={form.floor} onChange={function(e){set(\"floor\",e.target.value)}}>{FLOORS.map(function(f){return <option key={f}>{f}</option>})}</select></Field>\n      <Field label=\"Specific Location\"><input style={INP} value={form.location} onChange={function(e){set(\"location\",e.target.value)}} placeholder=\"e.g. NW Corner, Room 204\"/></Field>\n      <Field label=\"Unit Status\"><select style={SEL} value={form.status} onChange={function(e){set(\"status\",e.target.value)}}>{UNIT_STATUS.map(function(s){return <option key={s}>{s}</option>})}</select></Field>\n      <Field label=\"Install Date\"><input type=\"date\" style={INP} value={form.installDate} onChange={function(e){set(\"installDate\",e.target.value)}}/></Field>\n      <Field label=\"Last PM Date\"><input type=\"date\" style={INP} value={form.lastPM} onChange={function(e){handleLastPM(e.target.value)}}/></Field>\n      <Field label=\"Next PM (auto-set)\"><input type=\"date\" style={Object.assign({},INP,{color:form.nextPM?\"#22c55e\":\"#666\"})} value={form.nextPM} onChange={function(e){set(\"nextPM\",e.target.value)}}/></Field>\n      <Field label=\"PM Status\"><select style={SEL} value={form.pmStatus} onChange={function(e){set(\"pmStatus\",e.target.value)}}>{PM_LIST.map(function(s){return <option key={s}>{s}</option>})}</select></Field>\n    </div>\n    <div style={{borderTop:\"1px solid #222\",marginTop:\"0.5rem\",paddingTop:\"1rem\",marginBottom:\"0.5rem\"}}>\n      <div style={{fontSize:\"0.65rem\",color:\"#f59e0b\",letterSpacing:\"0.12em\",marginBottom:\"0.75rem\"}}>TECHNICAL SPECIFICATIONS</div>\n      <div style={{display:\"grid\",gridTemplateColumns:\"1fr 1fr\",gap:\"0 1rem\"}}>\n        <Field label=\"Volts\"><input style={INP} value={form.volts} onChange={function(e){set(\"volts\",e.target.value)}} placeholder=\"e.g. 208/230\"/></Field>\n        <Field label=\"Hz\"><input style={INP} value={form.hz} onChange={function(e){set(\"hz\",e.target.value)}} placeholder=\"e.g. 60\"/></Field>\n        <Field label=\"Comp RLA (amps)\"><input style={INP} type=\"number\" step=\"0.1\" value={form.compRLA} onChange={function(e){set(\"compRLA\",e.target.value)}} placeholder=\"e.g. 12.5\"/></Field>\n        <Field label=\"LRA (amps)\"><input style={INP} type=\"number\" step=\"0.1\" value={form.lra} onChange={function(e){set(\"lra\",e.target.value)}} placeholder=\"e.g. 68\"/></Field>\n        <Field label=\"Evap Fan Amps\"><input style={INP} type=\"number\" step=\"0.1\" value={form.evapFanAmps} onChange={function(e){set(\"evapFanAmps\",e.target.value)}} placeholder=\"e.g. 1.8\"/></Field>\n        <Field label=\"Refrigerant Type\"><input style={INP} value={form.refrigerantType} onChange={function(e){set(\"refrigerantType\",e.target.value)}} placeholder=\"e.g. R-410A\"/></Field>\n        <Field label=\"Total Charge (lbs)\"><input style={INP} type=\"number\" step=\"0.1\" value={form.totalCharge} onChange={function(e){set(\"totalCharge\",e.target.value)}} placeholder=\"e.g. 4.5\"/></Field>\n        <Field label=\"High Side PSI\"><input style={INP} type=\"number\" value={form.highSidePSI} onChange={function(e){set(\"highSidePSI\",e.target.value)}} placeholder=\"e.g. 400\"/></Field>\n        <Field label=\"Low Side PSI\"><input style={INP} type=\"number\" value={form.lowSidePSI} onChange={function(e){set(\"lowSidePSI\",e.target.value)}} placeholder=\"e.g. 120\"/></Field>\n      </div>\n    </div>\n    <Field label=\"Notes / Comments\"><textarea style={TA} value={form.notes} onChange={function(e){set(\"notes\",e.target.value)}} placeholder=\"Known issues, special instructions...\"/></Field>\n    <div style={{display:\"flex\",gap:\"0.75rem\",justifyContent:\"flex-end\",marginTop:\"0.5rem\"}}>\n      <button onClick={props.onClose} style={{background:\"none\",border:\"1px solid #333\",color:\"#777\",padding:\"0.5rem 1.1rem\",borderRadius:\"3px\",cursor:\"pointer\",fontSize:\"0.75rem\"}}>CANCEL</button>\n      <button onClick={handleSave} style={{background:\"#f59e0b\",border:\"none\",color:\"#000\",padding:\"0.5rem 1.25rem\",borderRadius:\"3px\",cursor:\"pointer\",fontSize:\"0.78rem\",fontWeight:\"bold\"}}>{unit?\"UPDATE UNIT\":\"REGISTER UNIT\"}</button>\n    </div>\n  </div>;\n}\n\nfunction LogForm(props){\n  const [form,setForm]=useState({type:\"PM\",date:localDate(),tech:\"\",description:\"\",refrigerantAdded:\"\",pressure:\"\"});\n  function set(k,v){setForm(function(f){return Object.assign({},f,{[k]:v})})}\n  const isRef=form.type===\"Refrigerant\"||/leak|low pressure|refrigerant|freon/i.test(form.description);\n  return <div>\n    <div style={{display:\"grid\",gridTemplateColumns:\"1fr 1fr\",gap:\"0 1rem\"}}>\n      <Field label=\"Entry Type\"><select style={SEL} value={form.type} onChange={function(e){set(\"type\",e.target.value)}}>{LOG_TYPES.map(function(t){return <option key={t}>{t}</option>})}</select></Field>\n      <Field label=\"Date\"><input type=\"date\" style={INP} value={form.date} onChange={function(e){set(\"date\",e.target.value)}}/></Field>\n      <Field label=\"Tech Initials\">\n        <div style={{display:\"flex\",alignItems:\"center\",gap:\"0.5rem\"}}>\n          <input style={Object.assign({},INP,{textTransform:\"uppercase\",letterSpacing:\"0.2em\",fontSize:\"1rem\",fontWeight:\"bold\",textAlign:\"center\",width:\"72px\",flexShrink:0})} value={form.tech} maxLength={2} onChange={function(e){set(\"tech\",e.target.value.toUpperCase().replace(/[^A-Z]/g,\"\"))}} placeholder=\"JD\"/>\n          {form.tech.length===2&&<div style={{width:\"34px\",height:\"34px\",borderRadius:\"50%\",background:\"#f59e0b\",display:\"flex\",alignItems:\"center\",justifyContent:\"center\",fontSize:\"0.75rem\",fontWeight:\"bold\",color:\"#000\"}}>{form.tech}</div>}\n          <span style={{fontSize:\"0.65rem\",color:\"#555\"}}>First 2 letters</span>\n        </div>\n      </Field>\n      {isRef&&<Field label=\"Refrigerant Added (lbs)\"><input style={INP} type=\"number\" step=\"0.1\" value={form.refrigerantAdded} onChange={function(e){set(\"refrigerantAdded\",e.target.value)}} placeholder=\"e.g. 2.5\"/></Field>}\n      {isRef&&<Field label=\"System Pressure (PSI)\"><input style={INP} type=\"number\" value={form.pressure} onChange={function(e){set(\"pressure\",e.target.value)}} placeholder=\"e.g. 150\"/></Field>}\n    </div>\n    <Field label=\"Description *\">\n      <textarea style={TA} value={form.description} onChange={function(e){set(\"description\",e.target.value)}} placeholder=\"Describe work done, parts replaced (compressor, capacitor, relay...), issues found...\"/>\n    </Field>\n    {form.type===\"PM\"&&<div style={{background:\"#0a1a0a\",border:\"1px solid #1a3a1a\",borderRadius:\"3px\",padding:\"0.65rem\",marginBottom:\"0.85rem\",fontSize:\"0.75rem\",color:\"#4ade80\"}}>PM logged = next PM auto-scheduled in 4 months.</div>}\n    <div style={{display:\"flex\",gap:\"0.75rem\",justifyContent:\"flex-end\"}}>\n      <button onClick={props.onClose} style={{background:\"none\",border:\"1px solid #333\",color:\"#777\",padding:\"0.5rem 1.1rem\",borderRadius:\"3px\",cursor:\"pointer\",fontSize:\"0.75rem\"}}>CANCEL</button>\n      <button onClick={function(){if(form.description)props.onSave(form)}} style={{background:form.type===\"PM\"?\"#22c55e\":form.type===\"Emergency\"?\"#ef4444\":\"#3b82f6\",border:\"none\",color:\"#000\",padding:\"0.5rem 1.25rem\",borderRadius:\"3px\",cursor:\"pointer\",fontSize:\"0.78rem\",fontWeight:\"bold\"}}>SAVE LOG</button>\n    </div>\n  </div>;\n}\n\nfunction AuthScreen(props){\n  const [mode,setMode]=useState(\"login\");\n  const [email,setEmail]=useState(\"\");\n  const [password,setPassword]=useState(\"\");\n  const [name,setName]=useState(\"\");\n  const [role,setRole]=useState(\"technician\");\n  const [loading,setLoading]=useState(false);\n  const [error,setError]=useState(\"\");\n  const [success,setSuccess]=useState(\"\");\n  function handle(){\n    setError(\"\");setSuccess(\"\");setLoading(true);\n    if(mode===\"login\"){\n      authSignIn(email,password).then(function(s){saveSession(s);props.onLogin(s)}).catch(function(e){setError(e.message);setLoading(false)});\n    }else{\n      authSignUp(email,password,name,role).then(function(){setSuccess(\"Account created! You can now log in.\");setMode(\"login\");setLoading(false)}).catch(function(e){setError(e.message);setLoading(false)});\n    }\n  }\n  return <div style={{minHeight:\"100vh\",background:\"#0a0a0a\",display:\"flex\",alignItems:\"center\",justifyContent:\"center\",padding:\"1rem\"}}>\n    <div style={{width:\"100%\",maxWidth:\"380px\"}}>\n      <div style={{textAlign:\"center\",marginBottom:\"2rem\"}}>\n        <div style={{fontSize:\"1.4rem\",fontWeight:\"bold\",color:\"#f59e0b\",letterSpacing:\"0.2em\"}}>HVAC TRACKER</div>\n        <div style={{fontSize:\"0.62rem\",color:\"#555\",letterSpacing:\"0.12em\",marginTop:\"0.3rem\"}}>HVAC MAINTENANCE MANAGEMENT SYSTEM</div>\n      </div>\n      <div style={{background:\"#111\",border:\"1px solid #2a2a2a\",borderRadius:\"6px\",padding:\"1.5rem\"}}>\n        <div style={{display:\"flex\",marginBottom:\"1.25rem\",border:\"1px solid #222\",borderRadius:\"4px\",overflow:\"hidden\"}}>\n          {[\"login\",\"signup\"].map(function(m){return <button key={m} onClick={function(){setMode(m);setError(\"\");setSuccess(\"\")}} style={{flex:1,padding:\"0.5rem\",background:mode===m?\"#f59e0b\":\"none\",border:\"none\",color:mode===m?\"#000\":\"#666\",cursor:\"pointer\",fontSize:\"0.75rem\",fontWeight:mode===m?\"bold\":\"normal\",textTransform:\"uppercase\"}}>{m===\"login\"?\"LOG IN\":\"SIGN UP\"}</button>})}\n        </div>\n        {mode===\"signup\"&&<div>\n          <div style={{marginBottom:\"0.75rem\"}}>\n            <label style={{display:\"block\",fontSize:\"0.62rem\",color:\"#777\",letterSpacing:\"0.1em\",marginBottom:\"0.3rem\"}}>FULL NAME</label>\n            <input style={Object.assign({},INP,{border:\"1px solid #2e2e2e\"})} value={name} onChange={function(e){setName(e.target.value)}} placeholder=\"John Smith\"/>\n          </div>\n          <div style={{marginBottom:\"0.75rem\"}}>\n            <label style={{display:\"block\",fontSize:\"0.62rem\",color:\"#777\",letterSpacing:\"0.1em\",marginBottom:\"0.3rem\"}}>ROLE</label>\n            <select style={Object.assign({},SEL,{border:\"1px solid #2e2e2e\"})} value={role} onChange={function(e){setRole(e.target.value)}}>\n              <option value=\"technician\">Technician</option>\n              <option value=\"admin\">Admin</option>\n            </select>\n          </div>\n        </div>}\n        <div style={{marginBottom:\"0.75rem\"}}>\n          <label style={{display:\"block\",fontSize:\"0.62rem\",color:\"#777\",letterSpacing:\"0.1em\",marginBottom:\"0.3rem\"}}>EMAIL</label>\n          <input type=\"email\" style={Object.assign({},INP,{border:\"1px solid #2e2e2e\"})} value={email} onChange={function(e){setEmail(e.target.value)}} placeholder=\"you@company.com\"/>\n        </div>\n        <div style={{marginBottom:\"1rem\"}}>\n          <label style={{display:\"block\",fontSize:\"0.62rem\",color:\"#777\",letterSpacing:\"0.1em\",marginBottom:\"0.3rem\"}}>PASSWORD</label>\n          <input type=\"password\" style={Object.assign({},INP,{border:\"1px solid #2e2e2e\"})} value={password} onChange={function(e){setPassword(e.target.value)}} placeholder=\"Min 6 characters\" onKeyDown={function(e){if(e.key===\"Enter\")handle()}}/>\n        </div>\n        {error&&<div style={{background:\"#1a0505\",border:\"1px solid #5a1010\",borderRadius:\"3px\",padding:\"0.6rem 0.75rem\",marginBottom:\"0.75rem\",fontSize:\"0.75rem\",color:\"#f87171\"}}>{error}</div>}\n        {success&&<div style={{background:\"#051a09\",border:\"1px solid #105a20\",borderRadius:\"3px\",padding:\"0.6rem 0.75rem\",marginBottom:\"0.75rem\",fontSize:\"0.75rem\",color:\"#4ade80\"}}>{success}</div>}\n        <button onClick={handle} disabled={loading} style={{width:\"100%\",background:loading?\"#333\":\"#f59e0b\",border:\"none\",color:loading?\"#666\":\"#000\",padding:\"0.6rem\",borderRadius:\"3px\",cursor:loading?\"not-allowed\":\"pointer\",fontWeight:\"bold\",fontSize:\"0.82rem\"}}>\n          {loading?\"Please wait...\":mode===\"login\"?\"LOG IN\":\"CREATE ACCOUNT\"}\n        </button>\n      </div>\n    </div>\n  </div>;\n}\n\nfunction App(){\n  const [session,setSession]=useState(function(){return getSession()});\n  const [user,setUser]=useState(null);\n  const [units,setUnits]=useState([]);\n  const [loading,setLoading]=useState(true);\n  const [saving,setSaving]=useState(false);\n  const [dbError,setDbError]=useState(\"\");\n  const [search,setSearch]=useState(\"\");\n  const [filterFloor,setFilterFloor]=useState(\"All\");\n  const [filterStatus,setFilterStatus]=useState(\"All\");\n  const [modal,setModal]=useState(null);\n  const [selectedUnit,setSelectedUnit]=useState(null);\n  const [addingLog,setAddingLog]=useState(false);\n\n  const token=session?session.access_token:\"\";\n  const isAdmin=user&&user.user_metadata&&user.user_metadata.role===\"admin\";\n  const userName=user?(user.user_metadata&&user.user_metadata.name?user.user_metadata.name:user.email):\"\";\n\n  useEffect(function(){\n    if(token){authGetUser(token).then(function(u){if(u)setUser(u);else{clearSess();setSession(null)}})}\n    else setLoading(false);\n  },[token]);\n\n  const loadUnits=useCallback(function(){\n    if(!token)return;\n    setLoading(true);setDbError(\"\");\n    dbGet(token).then(function(data){setUnits(data);setSelectedUnit(function(sel){return sel?data.find(function(u){return u.id===sel.id})||null:null})}).catch(function(e){setDbError(\"Could not connect: \"+e.message)}).finally(function(){setLoading(false)});\n  },[token]);\n\n  useEffect(function(){if(session)loadUnits();else setLoading(false)},[loadUnits,session]);\n\n  function handleLogin(s){saveSession(s);setSession(s)}\n  function handleLogout(){if(token)authSignOut(token);clearSess();setSession(null);setUser(null);setUnits([])}\n\n  if(!session)return <AuthScreen onLogin={handleLogin}/>;\n\n  function saveUnit(form){\n    setSaving(true);\n    if(modal&&modal.unit){\n      const updated=Object.assign({},modal.unit,form);\n      dbUpdate(token,updated).then(function(){setUnits(function(us){return us.map(function(u){return u.id===updated.id?updated:u})});setSelectedUnit(updated);setModal(null)}).catch(function(e){alert(\"Save failed: \"+e.message)}).finally(function(){setSaving(false)});\n    }else{\n      const n=Object.assign({},form,{id:Date.now().toString(),logs:[],createdAt:new Date().toISOString()});\n      dbSave(token,n).then(function(){setUnits(function(us){return us.concat([n])});setModal(null)}).catch(function(e){alert(\"Save failed: \"+e.message)}).finally(function(){setSaving(false)});\n    }\n  }\n\n  function deleteUnit(id){\n    if(!confirm(\"Delete this unit and all history?\"))return;\n    dbDelete(token,id).then(function(){setUnits(function(us){return us.filter(function(u){return u.id!==id})});setSelectedUnit(null)}).catch(function(e){alert(\"Delete failed: \"+e.message)});\n  }\n\n  function saveLog(log){\n    const entry=Object.assign({},log,{id:Date.now().toString()});\n    const unit=units.find(function(u){return u.id===selectedUnit.id});\n    const logs=(unit.logs||[]).concat([entry]);\n    let updated=Object.assign({},unit,{logs:logs});\n    if(log.type===\"PM\"&&log.date){updated.lastPM=log.date;updated.nextPM=addMonths(log.date,4);updated.pmStatus=\"Current\"}\n    dbUpdate(token,updated).then(function(){setUnits(function(us){return us.map(function(u){return u.id===updated.id?updated:u})});setSelectedUnit(updated)}).catch(function(e){alert(\"Save failed: \"+e.message)});\n    setAddingLog(false);\n  }\n\n  function deleteLog(idx){\n    const unit=units.find(function(u){return u.id===selectedUnit.id});\n    const updated=Object.assign({},unit,{logs:unit.logs.filter(function(_,i){return i!==idx})});\n    dbUpdate(token,updated).then(function(){setUnits(function(us){return us.map(function(u){return u.id===updated.id?updated:u})});setSelectedUnit(updated)}).catch(function(e){alert(\"Delete failed: \"+e.message)});\n  }\n\n  const filtered=units.filter(function(u){\n    const q=search.toLowerCase();\n    return(!q||[u.serialNumber,u.make,u.model,u.location,u.floor].some(function(v){return v&&v.toLowerCase().includes(q)}))&&(filterFloor===\"All\"||u.floor===filterFloor)&&(filterStatus===\"All\"||u.status===filterStatus);\n  });\n  const counts=UNIT_STATUS.reduce(function(acc,s){acc[s]=units.filter(function(u){return u.status===s}).length;return acc},{});\n  const criticalUnits=units.filter(function(u){return analyze(u).some(function(p){return p.level===\"critical\"})}).length;\n\n  return <div style={{minHeight:\"100vh\",background:\"#0a0a0a\",color:\"#e5e5e5\",fontFamily:\"Courier New,monospace\"}}>\n    <div style={{background:\"#0f0f0f\",borderBottom:\"2px solid #f59e0b\",padding:\"0.75rem 1.25rem\",display:\"flex\",alignItems:\"center\",justifyContent:\"space-between\",flexWrap:\"wrap\",gap:\"0.5rem\"}}>\n      <div>\n        <div style={{fontSize:\"0.95rem\",fontWeight:\"bold\",letterSpacing:\"0.18em\",color:\"#f59e0b\"}}>HVAC TRACKER</div>\n        <div style={{display:\"flex\",alignItems:\"center\",gap:\"0.5rem\",flexWrap:\"wrap\"}}>\n          <div style={{fontSize:\"0.58rem\",color:\"#555\",letterSpacing:\"0.1em\"}}>HVAC MAINTENANCE MANAGEMENT SYSTEM</div>\n          {loading&&<span style={{fontSize:\"0.58rem\",color:\"#f59e0b\"}}>Loading...</span>}\n          {saving&&<span style={{fontSize:\"0.58rem\",color:\"#22c55e\"}}>Saving...</span>}\n          {!loading&&!saving&&<span style={{fontSize:\"0.58rem\",color:\"#22c55e\"}}>CLOUD SYNC ON</span>}\n        </div>\n        {dbError&&<div style={{fontSize:\"0.62rem\",color:\"#f87171\",marginTop:\"2px\"}}>{dbError} <button onClick={loadUnits} style={{background:\"none\",border:\"none\",color:\"#f59e0b\",cursor:\"pointer\",fontSize:\"0.62rem\",textDecoration:\"underline\"}}>Retry</button></div>}\n      </div>\n      <div style={{display:\"flex\",gap:\"0.75rem\",alignItems:\"center\",flexWrap:\"wrap\"}}>\n        {criticalUnits>0&&<div style={{background:\"#2a0a0a\",border:\"1px solid #5a1010\",borderRadius:\"3px\",padding:\"0.25rem 0.6rem\",fontSize:\"0.65rem\",color:\"#f87171\"}}>{criticalUnits} NEED ATTENTION</div>}\n        {Object.entries(counts).map(function(entry){return <div key={entry[0]} style={{textAlign:\"center\"}}><div style={{fontSize:\"1rem\",fontWeight:\"bold\",color:SC[entry[0]]}}>{entry[1]}</div><div style={{fontSize:\"0.5rem\",color:\"#555\"}}>{entry[0].toUpperCase()}</div></div>})}\n        <div style={{textAlign:\"center\"}}>\n          <div style={{fontSize:\"0.7rem\",color:isAdmin?\"#f59e0b\":\"#22c55e\",fontWeight:\"bold\"}}>{isAdmin?\"ADMIN\":\"TECH\"}</div>\n          <div style={{fontSize:\"0.55rem\",color:\"#555\",maxWidth:\"70px\",overflow:\"hidden\",textOverflow:\"ellipsis\",whiteSpace:\"nowrap\"}}>{userName}</div>\n        </div>\n        <button onClick={loadUnits} style={{background:\"none\",border:\"1px solid #333\",color:\"#666\",padding:\"0.4rem 0.7rem\",borderRadius:\"3px\",cursor:\"pointer\",fontSize:\"0.7rem\"}}>\u21bb</button>\n        <button onClick={function(){setModal({type:\"add\"})}} style={{background:\"#f59e0b\",border:\"none\",color:\"#000\",padding:\"0.45rem 0.9rem\",borderRadius:\"3px\",cursor:\"pointer\",fontWeight:\"bold\",fontSize:\"0.75rem\"}}>+ ADD UNIT</button>\n        <button onClick={handleLogout} style={{background:\"none\",border:\"1px solid #444\",color:\"#888\",padding:\"0.45rem 0.75rem\",borderRadius:\"3px\",cursor:\"pointer\",fontSize:\"0.7rem\"}}>LOG OUT</button>\n      </div>\n    </div>\n\n    {loading&&<div style={{position:\"fixed\",inset:0,background:\"rgba(0,0,0,0.7)\",zIndex:2000,display:\"flex\",alignItems:\"center\",justifyContent:\"center\",flexDirection:\"column\",gap:\"1rem\"}}><div style={{fontSize:\"2rem\"}}>\u2699</div><div style={{color:\"#f59e0b\",fontSize:\"0.85rem\",letterSpacing:\"0.15em\"}}>LOADING FROM CLOUD...</div></div>}\n\n    <div style={{background:\"#111\",borderBottom:\"1px solid #1e1e1e\",padding:\"0.6rem 1.25rem\",display:\"flex\",gap:\"0.6rem\",flexWrap:\"wrap\",alignItems:\"center\"}}>\n      <input style={Object.assign({},INP,{width:\"200px\"})} placeholder=\"Search serial, make, location...\" value={search} onChange={function(e){setSearch(e.target.value)}}/>\n      <select style={Object.assign({},SEL,{width:\"140px\"})} value={filterFloor} onChange={function(e){setFilterFloor(e.target.value)}}><option value=\"All\">All Floors</option>{FLOORS.map(function(f){return <option key={f}>{f}</option>})}</select>\n      <select style={Object.assign({},SEL,{width:\"140px\"})} value={filterStatus} onChange={function(e){setFilterStatus(e.target.value)}}><option value=\"All\">All Statuses</option>{UNIT_STATUS.map(function(s){return <option key={s}>{s}</option>})}</select>\n      <span style={{marginLeft:\"auto\",fontSize:\"0.65rem\",color:\"#444\"}}>{filtered.length} / {units.length} UNITS</span>\n    </div>\n\n    <div style={{display:\"flex\",height:\"calc(100vh - 118px)\"}}>\n      <div style={{width:selectedUnit?\"340px\":\"100%\",borderRight:selectedUnit?\"1px solid #1e1e1e\":\"none\",overflowY:\"auto\",flexShrink:0}}>\n        {filtered.length===0?<div style={{padding:\"3rem\",textAlign:\"center\",color:\"#333\"}}><div style={{fontSize:\"2rem\",marginBottom:\"0.5rem\"}}>\u2699</div><div style={{fontSize:\"0.8rem\"}}>{units.length===0?\"No units yet \u2014 tap + ADD UNIT to start.\":\"No units match your search.\"}</div></div>\n        :filtered.map(function(unit){\n          const alerts=analyze(unit);\n          const hasCrit=alerts.some(function(a){return a.level===\"critical\"});\n          const hasWarn=alerts.some(function(a){return a.level===\"warning\"});\n          const pc=countParts(unit.logs||[]);\n          const hasCritPart=PARTS.some(function(p){return pc[p.key]>=3});\n          const borderColor=hasCrit||hasCritPart?\"#ef4444\":hasWarn?\"#f59e0b\":SC[unit.status]||\"#333\";\n          return <div key={unit.id} onClick={function(){setSelectedUnit(unit)}} style={{padding:\"0.8rem 1rem\",borderBottom:\"1px solid #141414\",cursor:\"pointer\",background:selectedUnit&&selectedUnit.id===unit.id?\"#191409\":\"transparent\",borderLeft:\"3px solid \"+borderColor}}>\n            <div style={{display:\"flex\",justifyContent:\"space-between\",alignItems:\"flex-start\"}}>\n              <div>\n                <div style={{display:\"flex\",alignItems:\"center\",gap:\"0.4rem\"}}>\n                  <span style={{fontSize:\"0.82rem\",fontWeight:\"bold\",color:\"#f59e0b\"}}>{unit.serialNumber}</span>\n                  {(hasCrit||hasCritPart)&&<span>\ud83d\udd34</span>}\n                  {!(hasCrit||hasCritPart)&&hasWarn&&<span>\ud83d\udfe1</span>}\n                </div>\n                <div style={{fontSize:\"0.75rem\",color:\"#aaa\",marginTop:\"2px\"}}>{unit.make}{unit.model?\" \u00b7 \"+unit.model:\"\"}</div>\n                <div style={{fontSize:\"0.65rem\",color:\"#666\",marginTop:\"2px\"}}>{unit.floor}{unit.location?\" \u2014 \"+unit.location:\"\"}</div>\n              </div>\n              <div style={{textAlign:\"right\",flexShrink:0}}>\n                <div style={{fontSize:\"0.62rem\",color:SC[unit.status]}}>{unit.status.toUpperCase()}</div>\n                <div style={{fontSize:\"0.58rem\",color:\"#444\",marginTop:\"3px\"}}>{unit.logs?unit.logs.length:0} logs</div>\n                {unit.nextPM&&<div style={{fontSize:\"0.58rem\",color:\"#555\",marginTop:\"2px\"}}>PM {fmtDate(unit.nextPM)}</div>}\n              </div>\n            </div>\n          </div>;\n        })}\n      </div>\n\n      {selectedUnit&&<div style={{flex:1,overflowY:\"auto\",padding:\"1rem 1.25rem\",minWidth:0}}>\n        <div style={{display:\"flex\",justifyContent:\"space-between\",alignItems:\"flex-start\",marginBottom:\"0.85rem\"}}>\n          <div>\n            <div style={{fontSize:\"0.95rem\",color:\"#f59e0b\",fontWeight:\"bold\",letterSpacing:\"0.1em\"}}>{selectedUnit.serialNumber}</div>\n            <div style={{fontSize:\"0.7rem\",color:\"#666\"}}>{selectedUnit.make} {selectedUnit.model} \u2014 {selectedUnit.floor}</div>\n          </div>\n          <div style={{display:\"flex\",gap:\"0.4rem\"}}>\n            {isAdmin&&<button onClick={function(){deleteUnit(selectedUnit.id)}} style={{background:\"none\",border:\"1px solid #2a0a0a\",color:\"#ef4444\",padding:\"0.3rem 0.65rem\",borderRadius:\"3px\",cursor:\"pointer\",fontSize:\"0.65rem\"}}>DELETE</button>}\n            <button onClick={function(){setSelectedUnit(null)}} style={{background:\"none\",border:\"1px solid #2a2a2a\",color:\"#666\",padding:\"0.3rem 0.65rem\",borderRadius:\"3px\",cursor:\"pointer\",fontSize:\"0.65rem\"}}>CLOSE</button>\n          </div>\n        </div>\n        <UnitDetail unit={selectedUnit} onEdit={function(){setModal({type:\"edit\",unit:selectedUnit})}} onAddLog={function(){setAddingLog(true)}} onDeleteLog={deleteLog} isAdmin={isAdmin}/>\n      </div>}\n    </div>\n\n    {modal&&modal.type===\"add\"&&<Modal title=\"Register New Unit\" onClose={function(){setModal(null)}}><UnitForm onSave={saveUnit} onClose={function(){setModal(null)}}/></Modal>}\n    {modal&&modal.type===\"edit\"&&<Modal title={\"Edit \u2014 \"+modal.unit.serialNumber} onClose={function(){setModal(null)}}><UnitForm unit={modal.unit} onSave={saveUnit} onClose={function(){setModal(null)}}/></Modal>}\n    {addingLog&&selectedUnit&&<Modal title={\"Service Log \u2014 \"+selectedUnit.serialNumber} onClose={function(){setAddingLog(false)}}><LogForm onSave={saveLog} onClose={function(){setAddingLog(false)}}/></Modal>}\n  </div>;\n}\n\nReactDOM.createRoot(document.getElementById(\"root\")).render(<App/>);\n</script>\n</body>\n</html>";

export default {
  async fetch(request,env){
    const url=new URL(request.url);
    if(request.method==="OPTIONS") return new Response(null,{headers:{"Access-Control-Allow-Origin":"*","Access-Control-Allow-Methods":"GET,POST,PATCH,DELETE,OPTIONS","Access-Control-Allow-Headers":"Content-Type,Authorization,apikey,Prefer,X-User-Token"}});
    if(url.pathname==="/"||url.pathname==="/index.html") return new Response(HTML,{headers:{"Content-Type":"text/html;charset=UTF-8"}});
    if(url.pathname.startsWith("/auth/")){
      const authPath=url.pathname.replace("/auth/","/auth/v1/")+url.search;
      const body=request.method!=="GET"?await request.text():undefined;
      const resp=await fetch(SUPABASE_URL+authPath,{method:request.method,headers:{"Content-Type":"application/json","apikey":SUPABASE_KEY},body});
      const txt=await resp.text();
      return new Response(txt,{status:resp.status,headers:{"Content-Type":"application/json","Access-Control-Allow-Origin":"*"}});
    }
    if(url.pathname.startsWith("/api/")){
      const token=request.headers.get("X-User-Token")||SUPABASE_KEY;
      const path=url.pathname.replace("/api/","/rest/v1/")+url.search;
      const body=request.method!=="GET"&&request.method!=="DELETE"?await request.text():undefined;
      const resp=await fetch(SUPABASE_URL+path,{method:request.method,headers:{"Content-Type":"application/json","apikey":SUPABASE_KEY,"Authorization":"Bearer "+token,"Prefer":request.headers.get("Prefer")||"return=representation","Accept":"application/json"},body});
      const txt=await resp.text();
      return new Response(txt,{status:resp.status,headers:{"Content-Type":"application/json","Access-Control-Allow-Origin":"*"}});
    }
    return new Response("Not found",{status:404});
  }
};